using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes back the provided message with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return a + b;
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { Logging = true, Caching = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://endpoints", Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists the available API endpoints and their status.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Status = "active", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Status = "active", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

